import{_ as t,o as l,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Scalers Reference","description":"","frontmatter":{},"headers":[],"relativePath":"ru/scalers/reference.md","filePath":"ru/scalers/reference.md"}'),d={name:"ru/scalers/reference.md"};function o(n,e,i,s,c,g){return l(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="scalers-reference" tabindex="-1"><i class="ph ph-sliders"></i> Scalers Reference <a class="header-anchor" href="#scalers-reference" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-sliders&quot;&gt;&lt;/i&gt; Scalers Reference&quot;">​</a></h1><p>Web Adaptive Performance включает набор специализированных скейлеров (модулей оптимизации). Индексатор автоматически выбирает, какой скейлер задействовать, опираясь на его <code>Visual Impact</code> и текущий тип Bottleneck (<code>Target</code>: CPU или GPU).</p><h2 id="матрица-совместимости" tabindex="-1">Матрица совместимости <a class="header-anchor" href="#матрица-совместимости" aria-label="Permalink to &quot;Матрица совместимости&quot;">​</a></h2><p>Ниже представлена матрица совместимости и описание всех доступных модулей.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Скейлер</th><th style="text-align:left;">Пайплайн</th><th style="text-align:left;">Target</th><th style="text-align:left;">Описание</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Resolution</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Снижает разрешение рендера, радикально уменьшая нагрузку на GPU Fillrate. <em>Подробности см. ниже.</em></td></tr><tr><td style="text-align:left;"><strong>Shadows Quality</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Поэтапно отключает тени.<br>В <strong>URP</strong> сначала отключает мягкие тени, затем тени от доп. источников, затем основные.<br>В <strong>BiRP</strong> переключает тени в режим <code>Hard Only</code>, а затем отключает их полностью.</td></tr><tr><td style="text-align:left;"><strong>Shadow Cascades</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU/GPU</td><td style="text-align:left;">Уменьшает количество каскадов теней. Снижает количество Draw Calls процессора и нагрузку на видеокарту.</td></tr><tr><td style="text-align:left;"><strong>Shadow Distance</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Сокращает дистанцию отрисовки теней.</td></tr><tr><td style="text-align:left;"><strong>Shadow Resolution</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Снижает разрешение теневых карт (Shadow Maps).</td></tr><tr><td style="text-align:left;"><strong>Anti Aliasing</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Уменьшает качество сглаживания (MSAA) вплоть до полного отключения.</td></tr><tr><td style="text-align:left;"><strong>LOD Bias</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Заставляет Unity переключаться на низкополигональные LOD-модели на меньшей дистанции от камеры.</td></tr><tr><td style="text-align:left;"><strong>Camera Clip</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Сокращает параметр <code>Far Clip Plane</code> у целевых камер, убирая из рендера дальние объекты.</td></tr><tr><td style="text-align:left;"><strong>Layer Culling</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU</td><td style="text-align:left;">Пропорционально уменьшает дистанцию отсечения (Culling Distance) для конкретных слоев объектов.</td></tr><tr><td style="text-align:left;"><strong>Physics Step</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU</td><td style="text-align:left;">Снижает частоту расчетов физики. Спасает производительность при тяжелой физике в браузере.</td></tr><tr><td style="text-align:left;"><strong>LUT</strong></td><td style="text-align:left;"><code>URP Only</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Снижает размер таблиц Color Grading (LUT) до минимального размера.</td></tr><tr><td style="text-align:left;"><strong>Mesh LOD Threshold</strong></td><td style="text-align:left;"><code>Unity 6+</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">Изменяет параметр <code>meshLodThreshold</code>, представленный в Unity 6.2, для агрессивного переключения LOD-ов.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Осторожно с Physics Step Scaler</p><p>Скейлер физики напрямую изменяет параметр <code>Time.fixedDeltaTime</code>. Если контроллер персонажа или игровая механика жестко завязаны на фиксированные кадры физики без интерполяции (Interpolation), движение объектов может стать прерывистым на низких уровнях качества.</p></div><div class="tip custom-block"><p class="custom-block-title">Сброс настроек скейлера</p><p>Если вы экспериментировали с параметрами скейлера (например, меняли <code>Min Bound</code> или <code>Max Level</code>) и хотите вернуть их к значениям по умолчанию, просто выключите и снова включите его тумблер в окне <em>Project Settings</em>. Плагин автоматически пересоздаст модуль с базовыми настройками.</p></div><h2 id="разбор-resolution-scaler" tabindex="-1">Разбор: Resolution Scaler <a class="header-anchor" href="#разбор-resolution-scaler" aria-label="Permalink to &quot;Разбор: Resolution Scaler&quot;">​</a></h2><p>Это самый мощный инструмент плагина, дающий наибольший прирост FPS. Его работа кардинально отличается в зависимости от используемого пайплайна.</p><h3 id="в-режиме-urp-universal-render-pipeline" tabindex="-1">В режиме URP (Universal Render Pipeline) <a class="header-anchor" href="#в-режиме-urp-universal-render-pipeline" aria-label="Permalink to &quot;В режиме URP (Universal Render Pipeline)&quot;">​</a></h3><p>В URP масштабирование работает максимально прозрачно. Плагин обращается напрямую к свойству <code>renderScale</code> внутри <code>UniversalRenderPipelineAsset</code>. Интерфейс (UI) при этом остается четким автоматически, так как URP умеет рендерить Canvas поверх смасштабированного 3D-мира.</p><h3 id="в-режиме-birp-built-in-render-pipeline" tabindex="-1">В режиме BiRP (Built-in Render Pipeline) <a class="header-anchor" href="#в-режиме-birp-built-in-render-pipeline" aria-label="Permalink to &quot;В режиме BiRP (Built-in Render Pipeline)&quot;">​</a></h3><p>Исторически в BiRP нет встроенной настройки Render Scale, которая бы работала в WebGL без поломки интерфейса или крашей (FBO Feedback Loop). WebAP решает эту проблему, предлагая две эксклюзивные стратегии на выбор.</p><h4 id="режим-1-nativebrowserscaling" tabindex="-1">Режим 1: NativeBrowserScaling <a class="header-anchor" href="#режим-1-nativebrowserscaling" aria-label="Permalink to &quot;Режим 1: NativeBrowserScaling&quot;">​</a></h4><p>Плагин масштабирует HTML-элемент <code>&lt;canvas&gt;</code> напрямую через Native Loop Spoofing (инъекция в параметры <code>devicePixelRatio</code> браузера).</p><ul><li><strong>Плюсы:</strong> Максимальная производительность, нулевой overhead (затраты) на стороне видеокарты.</li><li><strong>Минусы:</strong> Интерфейс игры размывается вместе с 3D-графикой. Режим работает только в собранном WebGL билде (в редакторе Unity изменений не будет).</li></ul><h4 id="режим-2-rendertexturescaling" tabindex="-1">Режим 2: RenderTextureScaling <a class="header-anchor" href="#режим-2-rendertexturescaling" aria-label="Permalink to &quot;Режим 2: RenderTextureScaling&quot;">​</a></h4><p>Плагин перенаправляет рендер целевых камер в сжатую общую текстуру и использует скрытую Compositor Camera для вывода изображения.</p><ul><li><strong>Плюсы:</strong> 3D мир масштабируется, а UI (текст, кнопки) остается кристально четким.</li><li><strong>Минусы:</strong> Добавляет незначительную нагрузку на GPU из-за операции Blit (копирование текстуры на экран).</li></ul><div class="info custom-block"><p class="custom-block-title">Исправление кликов мыши (Raycasts)</p><p>При использовании RenderTextureScaling виртуальные координаты экрана сжимаются. Чтобы клики мышкой по 3D-объектам продолжали работать корректно, плагин автоматически заменяет базовые <code>PhysicsRaycaster</code> и <code>Physics2DRaycaster</code> на целевых камерах на кастомные <code>WebScaledPhysicsRaycaster</code>. Точность попадания лучей сохраняется идеальной при любом масштабе.</p></div><h2 id="как-сохранить-четкость-ui-для-режима-birp-rendertexturescaling" tabindex="-1">Как сохранить четкость UI? (Для режима BiRP RenderTextureScaling) <a class="header-anchor" href="#как-сохранить-четкость-ui-для-режима-birp-rendertexturescaling" aria-label="Permalink to &quot;Как сохранить четкость UI? (Для режима BiRP RenderTextureScaling)&quot;">​</a></h2><p>Чтобы интерфейс оставался четким при масштабировании 3D-графики в BiRP при RenderTextureScaling, необходимо правильно настроить ваш Canvas. Выберите один из двух вариантов:</p><h3 id="вариант-1-screen-space-overlay-рекомендуемыи" tabindex="-1">Вариант 1: Screen Space - Overlay (Рекомендуемый) <a class="header-anchor" href="#вариант-1-screen-space-overlay-рекомендуемыи" aria-label="Permalink to &quot;Вариант 1: Screen Space - Overlay (Рекомендуемый)&quot;">​</a></h3><p>Самый простой и надежный метод. Плагин сделает всю работу автоматически.</p><ol><li>Выберите ваш <strong>Canvas</strong> в иерархии сцены.</li><li>В компоненте Canvas установите <strong>Render Mode</strong> на <code>Screen Space - Overlay</code>.<br><em>Результат:</em> Unity отрисует интерфейс поверх сжатого 3D-мира в 100% нативном разрешении.</li></ol><h3 id="вариант-2-screen-space-camera-для-сложных-слоев" tabindex="-1">Вариант 2: Screen Space - Camera (Для сложных слоев) <a class="header-anchor" href="#вариант-2-screen-space-camera-для-сложных-слоев" aria-label="Permalink to &quot;Вариант 2: Screen Space - Camera (Для сложных слоев)&quot;">​</a></h3><p>Используется, если вам необходимо смешивать 3D-модели, партиклы и UI. Вам потребуется разделить рендер на две камеры.</p><ol><li><strong>Главная камера (3D):</strong> Убедитесь, что ее тег указан в настройках <code>Target Tags</code> скейлера. В поле <code>Culling Mask</code> снимите галочку со слоя <strong>UI</strong>. Установите <code>Depth</code> равным <code>0</code>.</li><li><strong>UI Камера (Новая):</strong> Создайте новую камеру для отрисовки интерфейса. <strong>Не добавляйте</strong> ее тег в настройки скейлера. <ul><li>Установите <code>Clear Flags</code> в <code>Depth Only</code> (чтобы камера не затирала 3D-фон).</li><li>Установите <code>Culling Mask</code> только на слой <strong>UI</strong>.</li><li>Установите <code>Depth</code> равным <code>1</code> (выше, чем у главной камеры).</li></ul></li><li><strong>Настройка Canvas:</strong> Установите <strong>Render Mode</strong> на <code>Screen Space - Camera</code> и перетащите вашу новую UI Камеру в слот <code>Render Camera</code>.</li></ol>',28)])])}const f=t(d,[["render",o]]);export{h as __pageData,f as default};
